/**
 * @param {MxObject[]} taskStatusList
 * @returns {Promise.<void>}
 */
export async function JS_TaskList_OverallStatus(taskStatusList) {
	// BEGIN USER CODE
	//throw new Error("JavaScript action was not implemented");

	//console.warn(taskStatusList);

	const colors = {
		Grey: 0,
		Green: 1,
		Yellow: 2,
		Red: 3
	}
	var color = colors.Grey;
	var noSelect = false;

	//State - 1-Not Started, 2-InProgress, 3-Failed, 4-Complete

	if(taskStatusList != undefined){
		for (var i = 0; i < taskStatusList.length; i++) {
			if(taskStatusList[i].jsonData.attributes.Name.value != null){
				if (taskStatusList[i].jsonData.attributes.StatusTaskChanged.value == true) {
					// if task got changes, use taskcomplete or taskfailed to define the overall status color
					if(taskStatusList[i].jsonData.attributes.TaskComplete.value == true){
						if(colors.Green > color)
							color = colors.Green;
					}
					else if(taskStatusList[i].jsonData.attributes.TaskFailed.value == true){
						if(colors.Red > color)
							color = colors.Red;
					}
					else{
						if(colors.Yellow > color)
							color = colors.Yellow;
					}
				} else {
					// if task no changes, use state to define the overall status color
					if(taskStatusList[i].jsonData.attributes.State.value == 4){
						if(colors.Green > color)
							color = colors.Green;
					}
					else if(taskStatusList[i].jsonData.attributes.State.value == 3){
						if(colors.Red > color)
							color = colors.Red;
					}
					else{
						if(colors.Yellow > color)
							color = colors.Yellow;
					}
				}
			}
			else{
				noSelect = true;
			}
		}
	}
	else{
		color = colors.Grey;
	}

	if(noSelect){
		if(color == colors.Green)
			color = colors.Yellow;
	}

	var ts = document.getElementsByClassName("tasklist-flex-status-overall");
	//console.warn(ts);
	if(ts != undefined){
		//ts[0].style.border = "3px Solid Black";
		if(color == colors.Grey){
			//ts[0].style.color = "White";
			//ts[0].style.backgroundColor = "Grey";
			ts[0].style.border = "5px Solid #f0f0f0";
		}
		else if(color == colors.Green){
			//ts[0].style.color = "White";
			//ts[0].style.backgroundColor = "Green";
			ts[0].style.border = "5px Solid #edfbf5";
		}
		else if(color == colors.Yellow){
			//ts[0].style.color = "Black";
			//ts[0].style.backgroundColor = "Yellow";
			ts[0].style.border = "5px Solid #fff7cd";
		}
		else if(color == colors.Red){
			//ts[0].style.color = "White";
			//ts[0].style.backgroundColor = "Red";
			ts[0].style.border = "5px Solid #fbeeed";
		}
	}

	// var ddls = document.getElementsByTagName("select");
	// console.warn(ddls);
	// for (var i = 0; i < ddls.length; i++) {
	// 	for (var j = 0; j < ddls[i].options[j + 1].length + 1; j++) {
	// 		if(ddls[i].options[j + 1].text == selectableObjects[j].jsonData.attributes.Name.value){
	// 			//if(selectableObjects[j].jsonData.attributes.TaskComplete.value == false)
	// 				ddls[i].options[j + 1].style.backgroundColor = "Green";
	// 		}
	// 	}
	// }

	// END USER CODE
}
